mapper.select:
SELECT id, template_name, appraisal_cycle, cycle_value, applicable_dept_id, self_weight, self_start_time, self_end_time, supervisor_start_time, supervisor_end_time, publish_start_time, publish_end_time, template_status, description FROM appraisal_template WHERE is_deleted = 0
AND template_name LIKE CONCAT('%', #{templateName}, '%')
AND template_status = #{templateStatus}
AND appraisal_cycle = #{appraisalCycle}
ORDER BY id DESC
